[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/BAaR> ;
            sh:resultMessage "A subjectOf catalog record on a CDIF codelist must include dcterms:conformsTo <https://w3id.org/cdif/codelist/1.0>." ;
            sh:resultPath dcterms:conformsTo ;
            sh:resultSeverity sh:Violation ;
            sh:sourceConstraintComponent sh:HasValueConstraintComponent ;
            sh:sourceShape [ a sh:PropertyShape ;
                    sh:hasValue <https://w3id.org/cdif/codelist/1.0> ;
                    sh:message "A subjectOf catalog record on a CDIF codelist must include dcterms:conformsTo <https://w3id.org/cdif/codelist/1.0>." ;
                    sh:minCount 1 ;
                    sh:path dcterms:conformsTo ] ] .

